import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    best_node = None
    best_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(customer_pos - cur_truck_pos)
        time_to_customer = distance_to_customer / truck_speed
        wait_time = max(0, time_windows[i][0] - current_time)

        visited_count = 0
        for truck_pos in all_truck_pos:
            if np.array_equal(truck_pos, depot_pos):
                continue
            if np.linalg.norm(truck_pos - customer_pos) < distance_to_customer:
                visited_count += 1

        cost = distance_to_customer + wait_time + visited_count

        if current_time + time_to_customer + wait_time < time_windows[i][1]:
            if cost < best_cost:
                best_node = i
                best_cost = cost
        else:
            penalty = 10 * (time_windows[i][1] - current_time)
            if cost + penalty < best_cost:
                best_node = i
                best_cost = cost + penalty

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_total_waiting_time = np.inf

    for i, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(customer_pos - cur_truck_pos)
        arrival_time = current_time + (distance_to_customer / truck_speed)
        start_window, end_window = time_windows[i]

        if arrival_time < start_window:
            waiting_time = start_window - arrival_time
        elif arrival_time > end_window:
            waiting_time = np.inf
        else:
            waiting_time = 0

        total_waiting_time = waiting_time

        for pos in all_truck_pos:
            other_truck_distance = np.linalg.norm(customer_pos - pos)
            other_truck_arrival_time = current_time + (other_truck_distance / truck_speed)
            if other_truck_arrival_time < start_window:
                total_waiting_time += start_window - other_truck_arrival_time

        if total_waiting_time < min_total_waiting_time:
            min_total_waiting_time = total_waiting_time
            best_node = i

    return best_node
